import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import L from "leaflet";
import { fetchBuses } from "./api";
import "./BusMap.css"; // keep name exact

// Custom icons
const normalIcon = new L.Icon({
  iconUrl: "https://maps.gstatic.com/mapfiles/ms2/micons/green.png",
  iconSize: [32, 32],
});
const ghostIcon = new L.Icon({
  iconUrl: "https://maps.gstatic.com/mapfiles/ms2/micons/red.png",
  iconSize: [32, 32],
});

export default function BusMap() {
  const [buses, setBuses] = useState([]);

  const getData = async () => {
    const data = await fetchBuses();
    setBuses(data);
  };

  useEffect(() => {
    getData();
    const interval = setInterval(getData, 120000); // 2 min
    return () => clearInterval(interval);
  }, []);

  return (
    <MapContainer center={[40.7128, -74.006]} zoom={11} style={{ height: "600px", width: "100%" }}>
      {/* Plain white map */}
      <TileLayer
        url="https://tiles.stadiamaps.com/tiles/alidade_smooth_white/{z}/{x}/{y}{r}.png"
        attribution="&copy; Stadia Maps"
      />
      {buses.map((bus) => (
        <Marker
          key={bus.id}
          position={[bus.lat, bus.lon]}
          icon={bus.status === "Ghost" ? ghostIcon : normalIcon}
        >
          <Popup>
            Bus {bus.id} <br /> Route: {bus.route} <br /> Status: {bus.status}
          </Popup>
        </Marker>
      ))}
    </MapContainer>
  );
}
